package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

class CSVFormatTest {

    @Test
    void testIsCommentingEnabledWhenCommentStartIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat modifiedFormat = setCommentStart(format, null);
        assertFalse(modifiedFormat.isCommentingEnabled());
    }

    @Test
    void testIsCommentingEnabledWhenCommentStartIsChar() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat modifiedFormat = setCommentStart(format, '#');
        assertTrue(modifiedFormat.isCommentingEnabled());
    }

    @Test
    void testIsCommentingEnabledWhenCommentStartIsCharacterObject() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat modifiedFormat = setCommentStart(format, Character.valueOf('!'));
        assertTrue(modifiedFormat.isCommentingEnabled());
    }

    private CSVFormat setCommentStart(CSVFormat format, Character commentStart) throws Exception {
        Field field = CSVFormat.class.getDeclaredField("commentStart");
        field.setAccessible(true);

        // Because the field is final, create a new CSVFormat instance with the desired commentStart
        // Use the withCommentStart method instead of reflection to avoid final field modification
        if (commentStart == null) {
            return format.withCommentStart((Character) null);
        } else {
            return format.withCommentStart(commentStart);
        }
    }
}
